1. Install packages
1. install packages

## Page 24

npm install @reduxjs/toolkit react-redux
RTK Query is included inside Redux Toolkit, so you do not install a separate RTK Query package. redux-toolkit.js.org
2. Create a normal slice using createSlice
src/features/counter/counterSlice.js
import { createSlice } from "@reduxjs/toolkit";
const initialState = {
 value: 0,
};
const counterSlice = createSlice({
 name: "counter",
 initialState,
 reducers: {
 increment: (state) => {
 state.value += 1;
 },
 decrement: (state) => {
 state.value -= 1;
 },
 incrementByAmount: (state, action) => {
 state.value += action.payload;
 },
 reset: (state) => {
 state.value = 0;
 },
 },
});
export const {
 increment,
 decrement,
 incrementByAmount,
 reset,
} = counterSlice.actions;
export default counterSlice.reducer;
What this gives you
Because of createSlice , Redux Toolkit automatically creates:
increment()
decrement()
incrementByAmount(10)
reset()

## Page 25

And also creates the reducer internally. createSlice is the standard Redux Toolkit way to write Redux reducer logic and auto-generate matching
action creators. redux-toolkit.js.org
3. Create API slice using createApi
src/services/postsApi.js
import { createApi, fetchBaseQuery } from "@reduxjs/toolkit/query/react";
export const postsApi = createApi({
 reducerPath: "postsApi",
 baseQuery: fetchBaseQuery({
 baseUrl: "https://jsonplaceholder.typicode.com",
 }),
 tagTypes: ["Post"],
 endpoints: (builder) => ({
 getPosts: builder.query({
 query: () => "/posts",
 providesTags: ["Post"],
 }),
 getPostById: builder.query({
 query: (id) => `/posts/${id}`,
 providesTags: (result, error, id) => [
 { type: "Post", id },
 ],
 }),
 addPost: builder.mutation({
 query: (newPost) => ({
 url: "/posts",
 method: "POST",
 body: newPost,
 }),
 invalidatesTags: ["Post"],
 }),
 updatePost: builder.mutation({
 query: ({ id, ...updatedPost }) => ({
 url: `/posts/${id}`,
 method: "PUT",
 body: updatedPost,
 }),
 invalidatesTags: (result, error, arg) => [
 { type: "Post", id: arg.id },
 "Post",
 ],
 }),
 deletePost: builder.mutation({
 query: (id) => ({
 url: `/posts/${id}`,
 method: "DELETE",

## Page 26

}),
 invalidatesTags: ["Post"],
 }),
 }),
});
export const {
 useGetPostsQuery,
 useGetPostByIdQuery,
 useAddPostMutation,
 useUpdatePostMutation,
 useDeletePostMutation,
} = postsApi;
Important
This part:
import { createApi } from "@reduxjs/toolkit/query/react";
is the React-specific version. It automatically generates hooks like:
useGetPostsQuery()
