1. Retries in RTK Query createApi
RTK Query provides a built-in retry utility. You wrap your fetchBaseQuery with it. By default, RTK Query’s retry utility uses 5 attempts with
exponential backoff, but you can override it. Redux Toolkit
import { createApi, fetchBaseQuery, retry } from "@reduxjs/toolkit/query/react";
const baseQuery = fetchBaseQuery({
 baseUrl: "https://api.example.com",
});
const baseQueryWithRetry = retry(baseQuery, {
 maxRetries: 3,
});
export const apiSlice = createApi({
 reducerPath: "api",
 baseQuery: baseQueryWithRetry,
 endpoints: (builder) => ({
 getUsers: builder.query({
 query: () => "/users",
 }),
 getUserById: builder.query({
 query: (id) => `/users/${id}`,
 // endpoint-level override
 extraOptions: {
 maxRetries: 1,
 },
 }),
 }),
});

