<h3 id="threadpoolexecutor-for-io">ThreadPoolExecutor for I/O</h3>
<pre><code class="language-python">from concurrent.futures import ThreadPoolExecutor, as_completed
import boto3
s3 = boto3.client(&quot;s3&quot;)
def head_object(bucket_key):
 bucket, key = bucket_key
 return s3.head_object(Bucket=bucket, Key=key)
items = [(&quot;my-bucket&quot;, &quot;a.pdf&quot;), (&quot;my-bucket&quot;, &quot;b.pdf&quot;)]

