with ThreadPoolExecutor(max_workers=10) as executor:
 futures = [executor.submit(head_object, item) for item in items]
 for future in as_completed(futures):
 print(future.result())
</code></pre>
<h3 id="multiprocessing-for-cpu-heavy-work">Multiprocessing for CPU-heavy work</h3>
<pre><code class="language-python">from concurrent.futures import ProcessPoolExecutor
def convert_page(page_number):
 # CPU-heavy PDF/image conversion
 return page_number, f&quot;page-{page_number}.png&quot;
with ProcessPoolExecutor() as executor:
 for result in executor.map(convert_page, range(1, 11)):
 print(result)
</code></pre>
<h3 id="asyncio-basics">Asyncio basics</h3>
<pre><code class="language-python">import asyncio
async def fetch_user(user_id):
 await asyncio.sleep(1)
 return {&quot;id&quot;: user_id}
async def main():
 results = await asyncio.gather(
 fetch_user(1),
 fetch_user(2),
 fetch_user(3),
 )
 print(results)
asyncio.run(main())
</code></pre>
<h3 id="asyncio-with-taskgroup">Asyncio with TaskGroup</h3>
<pre><code class="language-python">import asyncio
async def process_item(item):
 await asyncio.sleep(1)
 return item * 2
async def main():
 async with asyncio.TaskGroup() as tg:
 tasks = [tg.create_task(process_item(i)) for i in range(5)]
 print([task.result() for task in tasks])
asyncio.run(main())
</code></pre>
<h3 id="important-interview-warning">Important interview warning</h3>
<p><code>boto3</code> is synchronous. Using <code>asyncio</code> with blocking <code>boto3</code> calls does 
not magically make it non-blocking. Options:</p>
<ol>
<li>Use threads for boto3 calls.</li>
<li>Use <code>asyncio.to_thread()</code> for blocking functions.</li>
<li>Use an async AWS library carefully if allowed.</li>
<li>Keep Lambda simple and rely on event-driven parallelism.</li>
</ol>
<pre><code class="language-python">import asyncio

