import boto3
s3 = boto3.client(&quot;s3&quot;)
def blocking_head(bucket, key):
 return s3.head_object(Bucket=bucket, Key=key)
async def main():
 result = await asyncio.to_thread(blocking_head, &quot;bucket&quot;, &quot;key&quot;)
 print(result)
</code></pre>
