| filter @message like /ERROR|Exception|Traceback/
| sort @timestamp desc
| limit 50
</code></pre>
<h3 id="group-by-request-id">Group by request id</h3>
<pre><code class="language-sql">fields @timestamp, correlation_id, message, status
| filter correlation_id = &quot;req-123&quot;
| sort @timestamp asc
</code></pre>
<h3 id="lambda-cold-start-approximation">Lambda cold start approximation</h3>
<pre><code class="language-sql">fields @timestamp, @message
| filter @message like /INIT_START|REPORT/
| sort @timestamp desc
| limit 100
</code></pre>
<h3 id="slow-requests">Slow requests</h3>
<pre><code class="language-sql">fields @timestamp, duration_ms, path, status_code
| filter duration_ms &gt; 1000
| sort duration_ms desc
| limit 50
</code></pre>
